module reg_with_enable(
    input clk,
    input reset,
    input enable,
    input [3:0] d,
    output reg [3:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 4'b0000;
        else if (enable)
            q <= d;
    end
endmodule
